// Monochrome sandbox-provider brand marks, keyed by provider id. Rendered
// with currentColor so they inherit the surrounding text tone — same
// approach (and same paths) as the landing page's fleet band
// (apps/web/src/pages/index.astro).
//
// Icon sources / licenses:
// - Cloudflare, Docker, Kubernetes, NVIDIA: Simple Icons
//   (https://simple-icons.org), CC0-1.0 — single-path 24-grid marks.
// - Subprocess: not a brand — a terminal glyph (lucide.dev, ISC) stands in.
// - E2B: no Simple Icons entry — square-bracket glyph echoing the "[ ]"
//   wordmark.
// - Anything unrecognized gets a neutral box glyph so BYOK/custom
//   providers still render an icon slot of consistent size.

interface Mark {
  mode: "fill" | "stroke";
  path: string;
}

