/** Official brand colors (simple-icons values), used when `colored` is set.
 *  Ids without an entry (generic glyphs like subprocess/litebox) stay on
 *  currentColor. Values chosen to stay legible on both light and dark bg. */
const BRAND_COLORS: Record<string, string> = {
  cloudflare: "#F38020",
  kubernetes: "#326CE5",
  k8s: "#326CE5",
  "k8s-bridge": "#326CE5",
  "k8s-remote": "#326CE5",
  "docker-compose": "#2496ED",
  openshell: "#76B900",
  "github-actions": "#2088FF",
  daytona: "#22C55E",
  e2b: "#F97316",
  // Channel marks — github intentionally has NO entry (its black silhouette
  // stays on currentColor so it stays legible on dark backgrounds).
  slack: "#E01E5A",
  telegram: "#26A5E4",
  linear: "#5E6AD2",
  firecrawl: "#F97316",
};

/** Official brand color for a mark id, or undefined when the mark should stay
 *  on currentColor (generic glyphs, github). Exposed so consumers that render
 *  their own brand dots (e.g. Console's agent integration tags) share one
 *  source of truth for the hex values instead of duplicating literals. */
export function brandColor(id: string): string | undefined {
  return BRAND_COLORS[id.trim().toLowerCase()];
}

export function ProviderMark({ id, className, colored }: { id: string; className?: string; colored?: boolean }) {
  const key = id.trim().toLowerCase();
  const mark = MARKS[key] ?? BOX;
  const brand = colored ? BRAND_COLORS[key] : undefined;
  return (
    <svg
      viewBox="0 0 24 24"
      className={className}
      style={brand ? { color: brand } : undefined}
      aria-hidden="true"
      {...(mark.mode === "fill"
        ? { fill: "currentColor" }
        : {
            fill: "none",
            stroke: "currentColor",
            strokeWidth: 2,
            strokeLinecap: "round" as const,
            strokeLinejoin: "round" as const,
          })}
    >
      <path d={mark.path} />
    </svg>
  );
}
